const body = $input.first().json.body;
if (body.event !== 'kosztorys.anomaly_detected') return [];

const entity = body.entity_data;
const score = entity.anomaly_score ? (entity.anomaly_score * 100).toFixed(0) : '?';

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: '⚠️ Anomalia cenowa wykryta!' } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: `*Kosztorys:*\n${entity.nazwa || '-'}` },
    { type: 'mrkdwn', text: `*Anomaly Score:*\n${score}%` },
    { type: 'mrkdwn', text: `*Wartość netto:*\n${entity.suma_netto ? Number(entity.suma_netto).toLocaleString('pl-PL') + ' PLN' : '-'}` },
    { type: 'mrkdwn', text: `*Zgłosił:*\n${body.triggered_by}` },
  ]},
  { type: 'actions', elements: [{
    type: 'button', text: { type: 'plain_text', text: '🔍 Otwórz w Terra-OS' },
    url: `${$env.TERRA_URL || 'http://localhost:3001'}/kosztorys/${body.entity_id}`
  }]}
];

return [{ json: { blocks } }];
